import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

const API_BASE = 'http://localhost:5000/api';

function App() {
  const [currentUser, setCurrentUser] = useState(null);
  const [products, setProducts] = useState([]);
  const [categories, setCategories] = useState([]);
  const [cart, setCart] = useState([]);
  const [currentSection, setCurrentSection] = useState('home');

  useEffect(() => {
    loadProducts();
    loadCategories();
    checkUserSession();
  }, []);

  const loadProducts = async () => {
    try {
      const response = await axios.get(`${API_BASE}/products`);
      setProducts(response.data);
    } catch (error) {
      console.error('Error loading products:', error);
    }
  };

  const loadCategories = () => {
    setCategories([
      {id: 1, name: 'Electronics'},
      {id: 2, name: 'Clothing'},
      {id: 3, name: 'Home'}
    ]);
  };

  const checkUserSession = () => {
    const savedUser = localStorage.getItem('currentUser');
    if (savedUser) {
      setCurrentUser(JSON.parse(savedUser));
    }
  };

  const login = async (email, password) => {
    try {
      const response = await axios.post(`${API_BASE}/auth/login`, {
        email, password
      });
      if (response.data.success) {
        setCurrentUser(response.data.user);
        localStorage.setItem('currentUser', JSON.stringify(response.data.user));
        setCurrentSection('home');
        alert('Login successful!');
      } else {
        alert('Invalid credentials');
      }
    } catch (error) {
      console.error('Login error:', error);
      alert('Login failed');
    }
  };

  const logout = () => {
    setCurrentUser(null);
    localStorage.removeItem('currentUser');
    setCurrentSection('home');
  };

  const addToCart = (product) => {
    const existingItem = cart.find(item => item.id === product.id);
    if (existingItem) {
      setCart(cart.map(item => 
        item.id === product.id 
          ? {...item, quantity: item.quantity + 1}
          : item
      ));
    } else {
      setCart([...cart, {...product, quantity: 1}]);
    }
    alert('Item added to cart!');
  };

  const removeFromCart = (productId) => {
    setCart(cart.filter(item => item.id !== productId));
  };

  const updateQuantity = (productId, change) => {
    setCart(prevCart => 
      prevCart.map(item => {
        if (item && item.id === productId) {
          const newQuantity = (item.quantity || 0) + change;
          return newQuantity <= 0 ? null : {...item, quantity: newQuantity};
        }
        return item;
      }).filter(item => item !== null)
    );
  };

  return (
    <div className="App">
      <Header 
        currentUser={currentUser} 
        cartCount={cart.reduce((sum, item) => sum + item.quantity, 0)}
        setCurrentSection={setCurrentSection}
        logout={logout}
      />

      {currentSection === 'home' && <Home categories={categories} setCurrentSection={setCurrentSection} />}
      {currentSection === 'products' && 
        <Products products={products} addToCart={addToCart} />}
      {currentSection === 'cart' && 
        <Cart cart={cart} removeFromCart={removeFromCart} updateQuantity={updateQuantity} setCurrentSection={setCurrentSection} />}
      {currentSection === 'checkout' && 
        <Checkout cart={cart} setCart={setCart} currentUser={currentUser} />}
      {currentSection === 'login' && <Login onLogin={login} />}
      {currentSection === 'admin' && currentUser?.role === 'admin' && 
        <Admin products={products} />}
    </div>
  );
}

const Header = ({ currentUser, cartCount, setCurrentSection, logout }) => (
  <header className="header">
    <div className="container">
      <div className="logo">
        <h1><i className="fas fa-store"></i> EcoStore</h1>
      </div>
      <nav className="nav">
        <a href="#" onClick={() => setCurrentSection('home')}>Home</a>
        <a href="#" onClick={() => setCurrentSection('products')}>Products</a>
        <a href="#" onClick={() => setCurrentSection('cart')}>Cart ({cartCount})</a>
        {currentUser ? (
          <>
            {currentUser.role === 'admin' && 
              <a href="#" onClick={() => setCurrentSection('admin')}>Admin</a>}
            <a href="#" onClick={logout}>Logout</a>
          </>
        ) : (
          <a href="#" onClick={() => setCurrentSection('login')}>Login</a>
        )}
      </nav>
    </div>
  </header>
);

const Home = ({ categories, setCurrentSection }) => (
  <section className="section active">
    <div className="hero">
      <h2>Welcome to EcoStore</h2>
      <p>Your one-stop shop with MERN Stack</p>
      <button onClick={() => setCurrentSection('products')} className="btn-primary">Shop Now</button>
    </div>
    <div className="container">
      <div className="categories">
        {categories.map(category => (
          <div key={category.id} className="category" onClick={() => setCurrentSection('products')}>
            <i className={`fas fa-${getCategoryIcon(category.name)}`}></i>
            <h3>{category.name}</h3>
          </div>
        ))}
      </div>
    </div>
  </section>
);

const Products = ({ products, addToCart }) => (
  <section className="section active">
    <div className="container">
      <div className="products-header">
        <h2>Products</h2>
      </div>
      <div className="products-grid">
        {products.map(product => (
          <div key={product.id} className="product-card">
            <img src={product.image_url} alt={product.name} className="product-image" />
            <div className="product-info">
              <div className="product-name">{product.name}</div>
              <div className="product-price">${parseFloat(product.price).toFixed(2)}</div>
              <div className="product-description">{product.description}</div>
              <div className={`stock-status ${product.stock > 0 ? 'in-stock' : 'out-of-stock'}`}>
                {product.stock > 0 ? `In Stock (${product.stock})` : 'Out of Stock'}
              </div>
              <button 
                onClick={() => addToCart(product)} 
                className="btn-primary"
                disabled={product.stock === 0}
              >
                Add to Cart
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  </section>
);

const Cart = ({ cart, removeFromCart, updateQuantity, setCurrentSection }) => {
  const total = cart.reduce((sum, item) => sum + (parseFloat(item.price || 0) * (item.quantity || 0)), 0);

  return (
    <section className="section active">
      <div className="container">
        <h2>Shopping Cart</h2>
        {!cart || cart.length === 0 ? (
          <p>Your cart is empty</p>
        ) : (
          <>
            {cart.filter(item => item && item.id).map(item => (
              <div key={item.id} className="cart-item">
                <img src={item.image_url || ''} alt={item.name || 'Product'} />
                <div className="cart-item-info">
                  <h4>{item.name || 'Unknown Product'}</h4>
                  <p>${parseFloat(item.price || 0).toFixed(2)} each</p>
                </div>
                <div className="cart-item-controls">
                  <div className="quantity-controls">
                    <button className="quantity-btn" onClick={() => updateQuantity(item.id, -1)}>-</button>
                    <span>{item.quantity || 0}</span>
                    <button className="quantity-btn" onClick={() => updateQuantity(item.id, 1)}>+</button>
                  </div>
                  <div>${(parseFloat(item.price || 0) * (item.quantity || 0)).toFixed(2)}</div>
                  <button onClick={() => removeFromCart(item.id)} className="btn-primary">Remove</button>
                </div>
              </div>
            ))}
            <div className="cart-summary">
              <div className="total">
                <h3>Subtotal: ${total.toFixed(2)}</h3>
                <button 
                  onClick={() => setCurrentSection('checkout')} 
                  className="btn-primary"
                  disabled={!cart || cart.length === 0}
                >
                  Proceed to Checkout
                </button>
              </div>
            </div>
          </>
        )}
      </div>
    </section>
  );
};

const Checkout = ({ cart, setCart, currentUser }) => {
  const [paymentMethod, setPaymentMethod] = useState('chapa');
  const [shippingInfo, setShippingInfo] = useState({
    fullName: '',
    phone: '',
    address: '',
    city: '',
    region: ''
  });

  const total = cart.reduce((sum, item) => sum + (parseFloat(item.price || 0) * (item.quantity || 0)), 0);
  const shippingCost = 50; // Fixed shipping cost
  const finalTotal = total + shippingCost;

  const handleInputChange = (e) => {
    setShippingInfo({
      ...shippingInfo,
      [e.target.name]: e.target.value
    });
  };

  const handleCheckout = async () => {
    if (!shippingInfo.fullName || !shippingInfo.phone || !shippingInfo.address) {
      alert('Please fill in all shipping information');
      return;
    }

    if (paymentMethod === 'chapa') {
      try {
        const chapaData = {
          amount: finalTotal,
          currency: 'ETB',
          email: currentUser?.email || 'test@example.com',
          first_name: shippingInfo.fullName.split(' ')[0],
          last_name: shippingInfo.fullName.split(' ')[1] || '',
          phone_number: shippingInfo.phone,
          tx_ref: `ecostore-${Date.now()}`,
          callback_url: 'http://localhost:3000/payment-success',
          return_url: 'http://localhost:3000/payment-success',
          customization: {
            title: 'EcoStore Payment',
            description: 'Payment for your order'
          }
        };

        const response = await axios.post('http://localhost:5000/api/payment/chapa', chapaData);

        if (response.data.status === 'success') {
          // Redirect to Chapa checkout
          window.location.href = response.data.data.checkout_url;
        } else {
          alert('Payment initialization failed');
        }
      } catch (error) {
        console.error('Chapa payment error:', error);
        alert('Payment failed. Please try again.');
      }
    } else {
      alert('Order placed successfully! You will pay on delivery.');
      setCart([]);
    }
  };

  return (
    <section className="section active">
      <div className="container">
        <h2>Checkout</h2>
        <div className="checkout-container">
          <div className="checkout-left">
            <div className="shipping-info">
              <h3>Shipping Information</h3>
              <input
                type="text"
                name="fullName"
                placeholder="Full Name"
                value={shippingInfo.fullName}
                onChange={handleInputChange}
                required
              />
              <input
                type="tel"
                name="phone"
                placeholder="Phone Number"
                value={shippingInfo.phone}
                onChange={handleInputChange}
                required
              />
              <input
                type="text"
                name="address"
                placeholder="Street Address"
                value={shippingInfo.address}
                onChange={handleInputChange}
                required
              />
              <input
                type="text"
                name="city"
                placeholder="City"
                value={shippingInfo.city}
                onChange={handleInputChange}
                required
              />
              <input
                type="text"
                name="region"
                placeholder="Region/State"
                value={shippingInfo.region}
                onChange={handleInputChange}
                required
              />
            </div>

            <div className="payment-methods">
              <h3>Payment Method</h3>
              <div className="payment-option">
                <input
                  type="radio"
                  id="chapa"
                  name="payment"
                  value="chapa"
                  checked={paymentMethod === 'chapa'}
                  onChange={(e) => setPaymentMethod(e.target.value)}
                />
                <label htmlFor="chapa">
                  Pay with Chapa (Online Payment)
                  <div style={{fontSize: '0.8rem', color: '#666', marginTop: '0.2rem'}}>
                    Test phones: 0911223344, 0922334455, 0933445566
                  </div>
                </label>
              </div>
              <div className="payment-option">
                <input
                  type="radio"
                  id="cash"
                  name="payment"
                  value="cash"
                  checked={paymentMethod === 'cash'}
                  onChange={(e) => setPaymentMethod(e.target.value)}
                />
                <label htmlFor="cash">Cash on Delivery</label>
              </div>
            </div>
          </div>

          <div className="checkout-right">
            <div className="order-summary">
              <h3>Order Summary</h3>
              {cart.map(item => (
                <div key={item.id} className="checkout-item">
                  <span>{item.name} x {item.quantity}</span>
                  <span>${(parseFloat(item.price || 0) * (item.quantity || 0)).toFixed(2)}</span>
                </div>
              ))}
              <div className="checkout-item">
                <span>Subtotal:</span>
                <span>${total.toFixed(2)}</span>
              </div>
              <div className="checkout-item">
                <span>Shipping:</span>
                <span>${shippingCost.toFixed(2)}</span>
              </div>
              <div className="checkout-total">
                <strong>Total: ${finalTotal.toFixed(2)}</strong>
              </div>
              <button onClick={handleCheckout} className="btn-primary checkout-btn">
                {paymentMethod === 'chapa' ? 'Pay with Chapa' : 'Place Order (Cash on Delivery)'}
              </button>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

